import React, { useEffect } from "react";

const SplashScreen = ({ onComplete }) => {
  useEffect(() => {
    const timer = setTimeout(() => {
      onComplete();
    }, 2500); // 2.5s delay

    return () => clearTimeout(timer);
  }, [onComplete]);

  return (
    <div className="fixed inset-0 bg-[#0f172a] text-cyan-300 flex justify-center items-center z-50 animate-fadeOut delay-[2500ms]">
      <h1 className="text-4xl md:text-6xl font-bold animate-zoomBounce tracking-widest">
        NEURAL NINJAS'S
      </h1>
    </div>
  );
};

export default SplashScreen;
